import React, { useState } from 'react';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import axios from 'axios';
import "./styles/calendar.css"

function App() {
  const [events, setEvents] = useState([]);

  const fetchHolidays = async (year) => {
    try {
      const res = await axios.get('/calendar/holidays', {
        params: { year }
      });

      const items = res.data?.response?.body?.items?.item;

      if (!items) {
        console.warn('공휴일 데이터 없음');
        return;
      }

      const formattedEvents = items.map(item => ({
        title: item.dateName,
        date: item.locdate.toString().replace(/^(\d{4})(\d{2})(\d{2})$/, '$1-$2-$3'),
        color: 'red',
      }));

      setEvents(formattedEvents);
    } catch (error) {
      console.error('공휴일 API 호출 실패:', error);
    }
  };

  return (
    <div id="calendar-container">
      <FullCalendar
        plugins={[dayGridPlugin]}
        initialView="dayGridMonth"
        height="auto"
        headerToolbar={{
          start: "prev next",
          center: "title",
          end: "dayGridMonth dayGridWeek",
        }}
        locale={'ko'}
        events={events}
        datesSet={(arg) => {
          const currentYear = arg.view.currentStart.getFullYear();
          console.log('📅 현재 보이는 연도:', currentYear);
          fetchHolidays(currentYear);
        }}
      />
    </div>
  );
}

export default App;
